import{_ as a,c as t,o as e,a5 as n,f3 as p,f4 as l,f5 as i,f6 as m,f7 as o}from"./chunks/framework.Dm71djiW.js";const v=JSON.parse('{"title":"OCR: Smart Paste and Selective Paste","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guide-ocr.md","filePath":"docs/guide-ocr.md","lastUpdated":1768967432000}'),r={name:"docs/guide-ocr.md"};function c(d,s,h,g,x,y){return e(),t("div",null,[...s[0]||(s[0]=[n('<h1 id="ocr-smart-paste-and-selective-paste" tabindex="-1">OCR: Smart Paste and Selective Paste <a class="header-anchor" href="#ocr-smart-paste-and-selective-paste" aria-label="Permalink to “OCR: Smart Paste and Selective Paste”">​</a></h1><p>Smart paste and selective paste are introduced in this guide, which allow you to seamlessly organize handwritten notes, PDF textbook/papers into Liii STEM.</p><h2 id="smart-paste" tabindex="-1">Smart Paste <a class="header-anchor" href="#smart-paste" aria-label="Permalink to “Smart Paste”">​</a></h2><p><strong>Shortcut</strong>: <code>Ctrl</code> + <code>Shift</code> + <code>V</code>/<code>Command</code> + <code>Shift</code> + <code>V</code></p><p>Smart Paste automatically selects the appropriate format to paste based on the current environment and clipboard content, such as pasting <span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mtext>LaTeX</mtext></mrow><annotation encoding="application/x-tex">\\LaTeX</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8988em;vertical-align:-0.2155em;"></span><span class="mord text"><span class="mord textrm">L</span><span class="mspace" style="margin-right:-0.36em;"></span><span class="vlist-t"><span class="vlist-r"><span class="vlist" style="height:0.6833em;"><span style="top:-2.905em;"><span class="pstrut" style="height:2.7em;"></span><span class="mord"><span class="mord textrm mtight sizing reset-size6 size3">A</span></span></span></span></span></span><span class="mspace" style="margin-right:-0.15em;"></span><span class="mord text"><span class="mord textrm">T</span><span class="mspace" style="margin-right:-0.1667em;"></span><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.4678em;"><span style="top:-2.7845em;"><span class="pstrut" style="height:3em;"></span><span class="mord"><span class="mord textrm">E</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.2155em;"><span></span></span></span></span><span class="mspace" style="margin-right:-0.125em;"></span><span class="mord textrm">X</span></span></span></span></span></span> code snippets or images into Liii STEM.</p><p>Refer to <a href="https://liiistem.com/docs/guide-magic-paste.html" target="_blank" rel="noreferrer">&quot;Magic Paste.&quot;</a> , which do lossless copy-paste from LLMs to Liii STEM.</p><h3 id="image-ocr-in-text-mode" tabindex="-1">Image OCR (In <em>Text Mode</em>) <a class="header-anchor" href="#image-ocr-in-text-mode" aria-label="Permalink to “Image OCR (In Text Mode)”">​</a></h3><p>Using the smart paste, Liii STEM automatically detects clipboard content and calls OCR to convert image content into Liii STEM format.</p><p><img src="'+p+'" alt=""></p><p style="text-align:center;">1.Paste from PDF </p><blockquote><p>Note:</p><ul><li>large image files may cause network issues</li><li>For macOS built-in screenshots, use Command + Ctrl + Shift + 4 (Command + Shift + 4 is known to cause issues)</li></ul></blockquote><h3 id="image-ocr-in-math-mode" tabindex="-1">Image OCR (In <em>Math Mode</em>) <a class="header-anchor" href="#image-ocr-in-math-mode" aria-label="Permalink to “Image OCR (In Math Mode)”">​</a></h3><p>In <strong><em>math mode</em></strong>, we provide a more convenient shortcut- no need to press Shift. Simply use <code>Ctrl</code>+<code>V</code>/<code>Command</code>+<code>V</code> to call OCR to do its smart paste job.</p><blockquote><p>Note:</p><ul><li><code>Ctrl</code>+<code>Shift</code>+<code>V</code>/<code>Command</code>+<code>Shift</code>+<code>V</code> also works in <em>math mode</em></li><li>This method is recommended when the image content consists entirely of mathematical formulas.</li></ul></blockquote><p><img src="'+l+'" alt=""></p><p style="text-align:center;">2.Paste handwritten notes into Liii STEM format</p><h3 id="latex-code-in-math-mode" tabindex="-1"><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mtext>LaTeX</mtext></mrow><annotation encoding="application/x-tex">\\LaTeX</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8988em;vertical-align:-0.2155em;"></span><span class="mord text"><span class="mord textrm">L</span><span class="mspace" style="margin-right:-0.36em;"></span><span class="vlist-t"><span class="vlist-r"><span class="vlist" style="height:0.6833em;"><span style="top:-2.905em;"><span class="pstrut" style="height:2.7em;"></span><span class="mord"><span class="mord textrm mtight sizing reset-size6 size3">A</span></span></span></span></span></span><span class="mspace" style="margin-right:-0.15em;"></span><span class="mord text"><span class="mord textrm">T</span><span class="mspace" style="margin-right:-0.1667em;"></span><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.4678em;"><span style="top:-2.7845em;"><span class="pstrut" style="height:3em;"></span><span class="mord"><span class="mord textrm">E</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.2155em;"><span></span></span></span></span><span class="mspace" style="margin-right:-0.125em;"></span><span class="mord textrm">X</span></span></span></span></span></span> Code (in Math Mode) <a class="header-anchor" href="#latex-code-in-math-mode" aria-label="Permalink to “Code (in Math Mode)”">​</a></h3><p>In <em>math mode</em>, if you are working with <span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mtext>LaTeX</mtext></mrow><annotation encoding="application/x-tex">\\LaTeX</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8988em;vertical-align:-0.2155em;"></span><span class="mord text"><span class="mord textrm">L</span><span class="mspace" style="margin-right:-0.36em;"></span><span class="vlist-t"><span class="vlist-r"><span class="vlist" style="height:0.6833em;"><span style="top:-2.905em;"><span class="pstrut" style="height:2.7em;"></span><span class="mord"><span class="mord textrm mtight sizing reset-size6 size3">A</span></span></span></span></span></span><span class="mspace" style="margin-right:-0.15em;"></span><span class="mord text"><span class="mord textrm">T</span><span class="mspace" style="margin-right:-0.1667em;"></span><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.4678em;"><span style="top:-2.7845em;"><span class="pstrut" style="height:3em;"></span><span class="mord"><span class="mord textrm">E</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.2155em;"><span></span></span></span></span><span class="mspace" style="margin-right:-0.125em;"></span><span class="mord textrm">X</span></span></span></span></span></span> code instead of images of text or formulas, you can copy <span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mtext>LaTeX</mtext></mrow><annotation encoding="application/x-tex">\\LaTeX</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8988em;vertical-align:-0.2155em;"></span><span class="mord text"><span class="mord textrm">L</span><span class="mspace" style="margin-right:-0.36em;"></span><span class="vlist-t"><span class="vlist-r"><span class="vlist" style="height:0.6833em;"><span style="top:-2.905em;"><span class="pstrut" style="height:2.7em;"></span><span class="mord"><span class="mord textrm mtight sizing reset-size6 size3">A</span></span></span></span></span></span><span class="mspace" style="margin-right:-0.15em;"></span><span class="mord text"><span class="mord textrm">T</span><span class="mspace" style="margin-right:-0.1667em;"></span><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.4678em;"><span style="top:-2.7845em;"><span class="pstrut" style="height:3em;"></span><span class="mord"><span class="mord textrm">E</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.2155em;"><span></span></span></span></span><span class="mspace" style="margin-right:-0.125em;"></span><span class="mord textrm">X</span></span></span></span></span></span> code and directly use Smart Paste. Liii STEM will automatically convert <span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mtext>LaTeX</mtext></mrow><annotation encoding="application/x-tex">\\LaTeX</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8988em;vertical-align:-0.2155em;"></span><span class="mord text"><span class="mord textrm">L</span><span class="mspace" style="margin-right:-0.36em;"></span><span class="vlist-t"><span class="vlist-r"><span class="vlist" style="height:0.6833em;"><span style="top:-2.905em;"><span class="pstrut" style="height:2.7em;"></span><span class="mord"><span class="mord textrm mtight sizing reset-size6 size3">A</span></span></span></span></span></span><span class="mspace" style="margin-right:-0.15em;"></span><span class="mord text"><span class="mord textrm">T</span><span class="mspace" style="margin-right:-0.1667em;"></span><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.4678em;"><span style="top:-2.7845em;"><span class="pstrut" style="height:3em;"></span><span class="mord"><span class="mord textrm">E</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.2155em;"><span></span></span></span></span><span class="mspace" style="margin-right:-0.125em;"></span><span class="mord textrm">X</span></span></span></span></span></span> into corresponding formulas in <em>math mode</em>.</p><p><img src="'+i+'" alt=""></p><p style="text-align:center;">3.Paste from LaTeX </p><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to “Summary”">​</a></h3><p>There are Three ways to use smart paste, here are differences:</p><ol><li><p>Working with LaTeX code: Use smart paste (<code>Ctrl</code>+<code>Shift</code>+<code>v</code>) <strong>in <em>math mode</em></strong>.</p></li><li><p>Working with images whose content are text and formulas: Use smart paste <strong>in <em>text mode</em></strong>.</p></li><li><p>Working with images whose content are formulas only: Use smart paste or just <code>Ctrl</code>+<code>v</code> <strong>in <em>math mode</em></strong>.</p></li></ol><h2 id="selective-paste" tabindex="-1">Selective Paste <a class="header-anchor" href="#selective-paste" aria-label="Permalink to “Selective Paste”">​</a></h2><p>Selective Paste provides different document type options based on your clipboard content and current environment.</p><ul><li>such as pasting Markdown content directly into Liii STEM.</li></ul><p><strong>Shortcut</strong>: <code>Ctrl</code> + <code>Alt</code> + <code>V</code>/<code>Command</code> + <code>Option</code> + <code>V</code></p><p><img src="'+m+'" alt=""></p><p style="text-align:center;">4.Select Markdown option to paste</p><p><img src="'+o+'" alt=""></p><p style="text-align:center;">5.Paste content of image by Selecting `OCR` option</p>',31)])])}const f=a(r,[["render",c]]);export{v as __pageData,f as default};
